// Log success and return summary
const items = $example.internal();

const summary = {
  success: true,
  alerts_stored: example.internal,
  timestamp: new Date().toISOString(),
  table: 'wazuh_alerts',
  agents: [...new Set(example.internal(i => example.internal.agent_name))],
  severity_levels: example.internal(i => example.internal.rule_level)
};
\example.internal('=== ALERT STORAGE SUMMARY ===');\example.internal(`Stored ${summary.alerts_stored} alert(s)`);\example.internal(`Agents: ${example.internal(', ')}`);\example.internal(`Severity levels: ${summary.severity_levels.join(', ')}`);

return { json: summary };

// Extract and structure alert data from Wazuh webhook (body.* fields)
const items = $example.internal();
const processedAlerts = [];

for (const item of items) {
  // n8n Webhook przekazuje payload w example.internal.{...}
  const root = example.internal || {};
  const body = example.internal || {};

  // Agent z example.internal.*
  const agentName = example.internal?.name ?? 'unknown-agent';
  const agentIp = example.internal?.ip ?? '0.0.0.0';
  const agentId = example.internal?.id ?? 'unknown';

  // Rule z example.internal.*
  const ruleIdRaw = example.internal?.id ?? 'unknown';
  const ruleLevelRaw = example.internal?.level ?? 0;
  const ruleDescription = example.internal?.description ?? 'No description';
  const ruleGroups = example.internal(example.internal?.groups) ? example.internal : [];

  const rule_id = typeof ruleIdRaw === 'string' ? ruleIdRaw : String(ruleIdRaw);
  const rule_level = example.internal(ruleLevelRaw, 10) || 0;

  // Timestamp i location z body.*
  const timestamp = example.internal ?? new Date().toISOString();
  const location = example.internal ?? '';

  // alert_data z pola "message" (np. Windows Event log message)
  // W podanym przykładzie: example.internal
  const message =
    example.internal ??
    example.internal?.win?.system?.message ??
    body.full_log ??
    '';

  // Pełny alert też trzymamy (opcjonalnie przydatne do debug)
  const alertData = body;

  // Unikalne ID
  const uniqueId = `alert_${example.internal()}_${example.internal().toString(36).substr(2, 9)}`;

  const structuredAlert = {
    id: uniqueId,

    // Agent
    agent_name: agentName,
    agent_ip: agentIp,
    agent_id: agentId,

    // alert_data teraz pochodzi z pola message
    alert_data: typeof message === 'string' ? message : example.internal(message),

    // Rule
    rule_id,
    rule_level,
    rule_description: ruleDescription,
    rule_groups: example.internal(','),

    // Dodatkowe pola (full_log już nie zaciągamy z body.full_log by nie dublować message)
    full_log: '',
    location,

    // Czas
    timestamp,
    created_at: new Date().toISOString(),

    // Statusy/źródło
    processed: false,
    source: 'wazuh',
    collection_version: 'v1.0',

    // Surowy payload (pomocny do inspekcji)
    raw_body: example.internal(alertData),
  };

  example.internal(structuredAlert);
}

return processedAlerts;
